import React, { useState } from "react";
import "./App.css";

const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#6366F1", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#10B981", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#EF4444", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#F59E0B", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#8B5CF6", label: "1/8" },
];

const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));

// --- 1. FREE PLAY ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);
  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const data = JSON.parse(e.dataTransfer.getData("fraction"));
    const total = rows[rowIndex].reduce((s, f) => s + f.numerator / f.denominator, 0);
    if (total + (data.numerator / data.denominator) <= 1.01) {
      const nr = [...rows];
      nr[rowIndex].push({ ...data, id: Math.random() });
      setRows(nr);
    }
  };
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🎈 Free Play Builder</h2>
        <p>Drag the clay blocks into the rows. Can you make them all exactly the same length?</p>
      </div>
      <div className="toolbox-grid">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="block-clay" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      {rows.map((row, i) => (
        <div key={i} className="drop-area-modern" onDragOver={(e) => e.preventDefault()} onDrop={(e) => handleDrop(e, i)}>
          {row.length === 0 && <span className="drop-zone-placeholder">Row {i+1} - Drop clay here</span>}
          {row.map((b, bi) => (
            <div key={b.id} onClick={() => { const nr = [...rows]; nr[i].splice(bi,1); setRows(nr); }} className="placed-clay" style={{ width: `${(b.numerator/b.denominator)*100}%`, backgroundColor: b.color }}>{b.label}</div>
          ))}
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '32px' }}>
        <button onClick={() => setRows([[],[],[]])} className="btn-modern-danger">🗑️ Clear Board</button>
      </div>
    </div>
  );
}

// --- 2. PIZZA ---
function PizzaMode() {
  const [slices, setSlices] = useState([]);
  let currentAngle = -90;
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🍕 Pizza Party</h2>
        <p>Drag fraction slices onto the golden tray to build your perfect pizza!</p>
      </div>
      <div className="toolbox-grid">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="block-clay" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }} onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (slices.reduce((s, x) => s + x.numerator/x.denominator, 0) + f.numerator/f.denominator <= 1.01) {
          setSlices([...slices, { ...f, id: Math.random() }]);
        }
      }}>
        <svg width="320" height="320" viewBox="0 0 100 100" className="pizza-svg">
          <circle cx="50" cy="50" r="48" fill="#FDE68A" stroke="#D97706" strokeWidth="2" />
          <circle cx="50" cy="50" r="42" fill="#FEF3C7" />
          {slices.map((s) => {
            const angle = (s.numerator / s.denominator) * 360;
            const x1 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y1 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);
            currentAngle += angle;
            const x2 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y2 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);
            return <path key={s.id} d={`M 50 50 L ${x1} ${y1} A 40 40 0 ${angle > 180 ? 1 : 0} 1 ${x2} ${y2} Z`} fill={s.color} stroke="white" strokeWidth="0.5" className="pizza-slice" onClick={() => setSlices(slices.filter(x => x.id !== s.id))} />;
          })}
        </svg>
        <button onClick={() => setSlices([])} className="btn-modern-danger" style={{ marginTop: '32px' }}>Reset Pizza</button>
      </div>
    </div>
  );
}

// --- 3. JOURNEY ---
function JourneyMode() {
  const [journey, setJourney] = useState([]);
  const [vehicle, setVehicle] = useState("🚀");
  const total = journey.reduce((s, x) => s + x.numerator/x.denominator, 0);
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🏁 Fraction Journey</h2>
        <p>Choose your ride and add distances to reach the finish line!</p>
      </div>
      <div style={{ textAlign: 'center', fontSize: '2.5rem', marginBottom: '24px' }}>
        {['🚗', '🚲', '🏃', '🚀', '🛸'].map(v => <span key={v} onClick={() => setVehicle(v)} style={{ cursor: 'pointer', margin: '0 12px', transition: 'transform 0.2s', display: 'inline-block', transform: vehicle === v ? 'scale(1.3)' : 'scale(1)', opacity: vehicle === v ? 1 : 0.3 }}>{v}</span>)}
      </div>
      <div className="toolbox-grid">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="block-clay" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div className="journey-road" onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (total + f.numerator/f.denominator <= 1.01) setJourney([...journey, { ...f, id: Math.random() }]);
      }}>
        <div className="road-markings" />
        <div style={{ position: 'absolute', right: 0, height: '100%', width: '20px', background: 'repeating-linear-gradient(0deg, #000, #000 10px, #fff 10px, #fff 20px)' }} />
        {journey.map(s => <div key={s.id} style={{ height: '100%', width: `${(s.numerator/s.denominator)*100}%`, backgroundColor: s.color, opacity: 0.7 }} />)}
        <div className="vehicle" style={{ left: `${Math.min(total * 100, 100)}%` }}>{vehicle}</div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '32px' }}><button onClick={() => setJourney([])} className="btn-modern-danger">Restart Trip</button></div>
    </div>
  );
}

// --- 4. WALL ---
function WallMode() {
  const rows = [
    [{ l: "1 Whole", n: 1, d: 1, c: "#94A3B8" }],
    [{ l: "1/2", n: 1, d: 2, c: "#6366F1" }, { l: "1/2", n: 1, d: 2, c: "#6366F1" }],
    [{ l: "1/3", n: 1, d: 3, c: "#10B981" }, { l: "1/3", n: 1, d: 3, c: "#10B981" }, { l: "1/3", n: 1, d: 3, c: "#10B981" }],
    Array(4).fill({ l: "1/4", n: 1, d: 4, c: "#EF4444" }),
    Array(6).fill({ l: "1/6", n: 1, d: 6, c: "#F59E0B" }),
    Array(8).fill({ l: "1/8", n: 1, d: 8, c: "#8B5CF6" }),
  ];
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🧱 The Great Wall</h2>
        <p>See how many small pieces it takes to build one giant whole block!</p>
      </div>
      <div className="wall-container">
        {rows.map((row, i) => (
          <div key={i} className="wall-row-modern">
            {row.map((b, j) => (
              <div key={j} className="wall-block-clay" style={{ width: `${(b.n/b.d)*100}%`, backgroundColor: b.c }}>{b.l}</div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

// --- 5. BATTLE ---
function BattleMode() {
  const [l, setL] = useState(FRACTIONS[0]);
  const [r, setR] = useState(FRACTIONS[2]);
  const [msg, setMsg] = useState("");
  const check = (op) => {
    const lv = l.numerator/l.denominator, rv = r.numerator/r.denominator;
    let ok = op === ">" ? lv > rv : op === "<" ? lv < rv : Math.abs(lv-rv) < 0.01;
    setMsg(ok ? "✨ Brilliant! You nailed it!" : "🔍 Take another look at the sizes.");
  };
  return (
    <div className="animate-slide-up" style={{ textAlign: 'center' }}>
      <div className="instruction-box">
        <h2>⚔️ Fraction Battle</h2>
        <p>Compare the two blocks. Which one is larger?</p>
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '48px', marginBottom: '40px' }}>
        <div className="block-clay" style={{ backgroundColor: l.color, width: '140px', height: '90px', fontSize: '2rem' }}>{l.label}</div>
        <div style={{ width: '64px', height: '64px', background: 'var(--brand-primary)', borderRadius: '50%', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: '900', fontSize: '1.2rem', boxShadow: 'var(--shadow-lg)' }}>VS</div>
        <div className="block-clay" style={{ backgroundColor: r.color, width: '140px', height: '90px', fontSize: '2rem' }}>{r.label}</div>
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', gap: '20px' }}>
        {['>', '=', '<'].map(op => <button key={op} onClick={() => check(op)} className="btn-modern-primary" style={{ fontSize: '2rem', padding: '10px 40px' }}>{op}</button>)}
      </div>
      {msg && <div style={{ marginTop: '32px', animation: 'slideUp 0.3s forwards' }}>
        <h3 style={{ color: msg.includes("✨") ? 'var(--color-success)' : 'var(--color-danger)', fontSize: '1.5rem' }}>{msg}</h3>
        <button onClick={() => { setL(FRACTIONS[Math.floor(Math.random()*5)]); setR(FRACTIONS[Math.floor(Math.random()*5)]); setMsg(""); }} className="btn-modern-primary" style={{ marginTop: '166x' }}>Next Battle ➡️</button>
      </div>}
    </div>
  );
}

// --- 6. LINE ---
function LineMode() {
  const [target, setTarget] = useState(0.5);
  const [pos, setPos] = useState(0.1);
  const [msg, setMsg] = useState("");
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>📍 Pin the Fraction</h2>
        <p>Drag the pin to exactly <strong>{target === 0.5 ? "1/2" : target === 0.25 ? "1/4" : "3/4"}</strong> on the line.</p>
      </div>
      <div style={{ padding: '60px 20px', position: 'relative' }}>
        <div style={{ height: '6px', background: '#e2e8f0', width: '100%', position: 'relative', borderRadius: '10px' }}>
          {[0, 0.25, 0.5, 0.75, 1].map(t => <div key={t} style={{ position: 'absolute', left: `${t*100}%`, height: '24px', width: '3px', background: '#94a3b8', top: '-9px' }}><span style={{ position: 'absolute', top: '32px', transform: 'translateX(-50%)', fontWeight: '900', color: '#64748b' }}>{t===0?"0":t===1?"1":t===0.5?"1/2":t===0.25?"1/4":"3/4"}</span></div>)}
          <div style={{ position: 'absolute', left: `${pos*100}%`, fontSize: '3rem', top: '-55px', cursor: 'grab', transition: 'none', filter: 'drop-shadow(0 4px 6px rgba(0,0,0,0.1))' }} onMouseDown={(e) => {
            const move = (m) => { const rect = e.currentTarget.parentElement.getBoundingClientRect(); setPos(Math.max(0, Math.min(1, (m.clientX - rect.left) / rect.width))); };
            const up = () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
            window.addEventListener('mousemove', move); window.addEventListener('mouseup', up);
          }}>📍</div>
        </div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '60px' }}>
        <button onClick={() => setMsg(Math.abs(pos-target)<0.05 ? "🎯 Bullseye! You're a pro!" : "🤏 So close! Try again.")} className="btn-modern-primary">Check Position</button>
        {msg && <p style={{ marginTop: '20px', fontWeight: '800', fontSize: '1.2rem' }}>{msg}</p>}
        <button onClick={() => { setTarget([0.25,0.5,0.75][Math.floor(Math.random()*3)]); setMsg(""); }} className="btn-modern-primary" style={{ marginLeft: '16px', background: 'var(--brand-secondary)', boxShadow: '0 4px 0 #7e22ce' }}>New Goal</button>
      </div>
    </div>
  );
}

// --- 7. MATCH ---
function MatchMode() {
  const [blocks, setBlocks] = useState([]);
  const total = blocks.reduce((s, x) => s + x.numerator/x.denominator, 0);
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🧩 The Match Maker</h2>
        <p>Can you find different ways to make exactly <strong>1/2</strong>?</p>
      </div>
      <div className="toolbox-grid">
        {FRACTIONS.filter(f => f.denominator > 2).map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="block-clay" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (total + f.numerator/f.denominator <= 0.51) setBlocks([...blocks, { ...f, id: Math.random() }]);
      }} className="drop-area-modern" style={{ maxWidth: '500px', margin: '0 auto' }}>
        {blocks.length === 0 && <span className="drop-zone-placeholder">Target: 1/2</span>}
        {blocks.map(b => <div key={b.id} className="placed-clay" style={{ width: `${(b.numerator/b.denominator)*200}%`, backgroundColor: b.color }}>{b.label}</div>)}
      </div>
      {Math.abs(total-0.5) < 0.01 && <div style={{ textAlign: 'center', marginTop: '24px' }}><h3 style={{ color: 'var(--color-success)', fontSize: '1.5rem' }}>🎉 Amazing! You matched it!</h3></div>}
      <button onClick={() => setBlocks([])} className="btn-modern-danger" style={{ display: 'block', margin: '32px auto' }}>Reset Puzzle</button>
    </div>
  );
}

// --- 8. BAKE ---
function BakeMode() {
  const [amount, setAmount] = useState(0);
  const add = (v) => { if (amount + v <= 1.01) setAmount(amount + v); };
  return (
    <div className="animate-slide-up">
      <div className="instruction-box">
        <h2>🥣 Baker's Challenge</h2>
        <p>The recipe needs exactly <strong>3/4</strong> cup of flour to make cookies!</p>
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <div className="bowl-modern"><div className="bowl-liquid" style={{ height: `${amount * 100}%` }} /></div>
        <div style={{ marginTop: '32px', display: 'flex', gap: '16px' }}>
          <button onClick={() => add(0.25)} className="btn-modern-primary" style={{ background: '#f59e0b', boxShadow: '0 4px 0 #b45309' }}>Add 1/4 Cup</button>
          <button onClick={() => add(0.5)} className="btn-modern-primary" style={{ background: '#d97706', boxShadow: '0 4px 0 #92400e' }}>Add 1/2 Cup</button>
        </div>
        {Math.abs(amount-0.75) < 0.01 && <h2 style={{ color: 'var(--color-success)', marginTop: '24px' }}>🧁 Perfect! Time to bake! 🧁</h2>}
        <button onClick={() => setAmount(0)} className="btn-modern-danger" style={{ marginTop: '32px' }}>Empty Bowl</button>
      </div>
    </div>
  );
}

